using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator = new();

    // ── CalculateTotal: inline DataRow tests ──────────────────────────

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 3, 0.0, 30.00, DisplayName = "Multiple items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 4, 0.08, 110.16, DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00, 5, 0.15, 0.00, DisplayName = "Zero price")]
    [DataRow(99.99, 0, 0.20, 0.00, DisplayName = "Zero quantity")]
    [DataRow(100.00, 1, 1.0, 200.00, DisplayName = "Max tax rate (100%)")]
    public void CalculateTotal_ValidInputs_ReturnsExpectedTotal(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // ── CalculateTotal: DynamicData with ValueTuples ──────────────────

    [TestMethod]
    [DynamicData(nameof(InvalidCalculateTotalData))]
    public void CalculateTotal_InvalidInputs_ThrowsArgumentOutOfRange(
        decimal unitPrice, int quantity, decimal taxRate, string expectedParam)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(unitPrice, quantity, taxRate));

        Assert.AreEqual(expectedParam, ex.ParamName);
    }

    public static IEnumerable<(decimal unitPrice, int quantity, decimal taxRate, string expectedParam)>
        InvalidCalculateTotalData =>
    [
        (-1m, 1, 0.1m, "unitPrice"),
        (10m, -1, 0.1m, "quantity"),
        (10m, 1, -0.01m, "taxRate"),
        (10m, 1, 1.01m, "taxRate"),
    ];

    // ── ApplyDiscount: inline DataRow tests ───────────────────────────

    [TestMethod]
    [DataRow(100.00, 0.0, 100.00, DisplayName = "No discount")]
    [DataRow(100.00, 10.0, 90.00, DisplayName = "10% discount")]
    [DataRow(100.00, 50.0, 50.00, DisplayName = "50% discount")]
    [DataRow(100.00, 100.0, 0.00, DisplayName = "100% discount (free)")]
    [DataRow(59.99, 25.0, 44.9925, DisplayName = "Fractional result")]
    [DataRow(0.00, 50.0, 0.00, DisplayName = "Zero price, any discount")]
    public void ApplyDiscount_ValidInputs_ReturnsDiscountedPrice(
        double price, double discountPercent, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expected, result);
    }

    // ── ApplyDiscount: DynamicData for invalid inputs ─────────────────

    [TestMethod]
    [DynamicData(nameof(InvalidDiscountData))]
    public void ApplyDiscount_InvalidDiscount_ThrowsArgumentOutOfRange(
        decimal price, decimal discountPercent)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(price, discountPercent));

        Assert.AreEqual("discountPercent", ex.ParamName);
    }

    public static IEnumerable<(decimal price, decimal discountPercent)> InvalidDiscountData =>
    [
        (100m, -1m),
        (100m, 100.01m),
        (50m, -0.01m),
    ];

    // ── FormatPrice ───────────────────────────────────────────────────

    [TestMethod]
    [DataRow(19.99, "$", "$19.99", DisplayName = "USD")]
    [DataRow(19.99, "€", "€19.99", DisplayName = "Euro")]
    [DataRow(1000.5, "$", "$1000.50", DisplayName = "Pads to two decimals")]
    [DataRow(0.00, "£", "£0.00", DisplayName = "Zero with pound sign")]
    public void FormatPrice_WithSymbol_ReturnsFormattedString(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void FormatPrice_DefaultSymbol_UsesDollarSign()
    {
        var result = _calculator.FormatPrice(9.99m);

        Assert.StartsWith("$", result);
        Assert.AreEqual("$9.99", result);
    }
}

